{"code": "import json
from collections import defaultdict

children_books = locals()['var_functions.query_db:16']
reviews_path = locals()['var_functions.query_db:34']

book_info = {}
for book in children_books:
    book_info[book['book_id']] = book

with open(reviews_path, 'r') as f:
    reviews = json.load(f)

book_ratings = defaultdict(list)
for review in reviews:
    pid = review['purchase_id']
    if pid.startswith('purchaseid_'):
        bid = 'bookid_' + pid.split('_')[1]
        if bid in book_info:
            book_ratings[bid].append(float(review['rating']))

results = []
for bid, ratings in book_ratings.items():
    if ratings:
        avg = sum(ratings) / len(ratings)
        if avg >= 4.5:
            results.append({
                'book_id': bid,
                'title': book_info[bid]['title'],
                'average_rating': round(avg, 2),
                'review_count': len(ratings),
                'categories': book_info[bid]['categories']
            })

results.sort(key=lambda x: x['average_rating'], reverse=True)
print('__RESULT__:')
print(json.dumps(results))"}
